@import '../../utils/control-density.css';
@import '../../utils/shimmer.css';

:host {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  min-width: 0;
  vertical-align: middle;
}

.skeleton__shape {
  display: block;
  width: 100%;
  height: 100%;
  flex: 0 0 auto;
  background-color: var(--ds-shimmer-surface-base, var(--color-shimmer-fade));
  border-radius: var(--dimension-radius-025);
}

/* ── Text ──────────────────────────────────────────────────────────────── */

:host(.skeleton--text) {
  width: 100%;
  height: var(--ds-skeleton-canvas-size);
  padding-block: var(--dimension-space-025);
}

:host(.skeleton--text) .skeleton__shape {
  height: calc(var(--ds-skeleton-canvas-size) - var(--dimension-space-050));
}

:host(.skeleton--text-text-display-medium) { --ds-skeleton-canvas-size: var(--typography-lineheight-3xl); }
:host(.skeleton--text-text-display-small)  { --ds-skeleton-canvas-size: var(--typography-lineheight-2xl); }
:host(.skeleton--text-text-title-large)    { --ds-skeleton-canvas-size: var(--typography-lineheight-xl); }
:host(.skeleton--text-text-title-medium),
:host(.skeleton--text-text-body-large)     { --ds-skeleton-canvas-size: var(--typography-lineheight-lg); }
:host(.skeleton--text-text-title-small),
:host(.skeleton--text-text-body-medium)    { --ds-skeleton-canvas-size: var(--typography-lineheight-md); }
:host(.skeleton--text-text-body-small)     { --ds-skeleton-canvas-size: var(--typography-lineheight-sm); }
:host(.skeleton--text-text-caption)        { --ds-skeleton-canvas-size: var(--typography-lineheight-xs); }

/* ── Icon ──────────────────────────────────────────────────────────────── */

:host(.skeleton--icon) {
  width: var(--ds-skeleton-canvas-size);
  height: var(--ds-skeleton-canvas-size);
  padding: var(--dimension-space-025);
}

:host(.skeleton--icon) .skeleton__shape {
  width: calc(var(--ds-skeleton-canvas-size) - var(--dimension-space-050));
  height: calc(var(--ds-skeleton-canvas-size) - var(--dimension-space-050));
}

:host(.skeleton--icon.skeleton--rounded) .skeleton__shape {
  border-radius: var(--dimension-radius-half);
}

:host(.skeleton--icon-xs)  { --ds-skeleton-canvas-size: var(--dimension-iconography-xs); }
:host(.skeleton--icon-sm)  { --ds-skeleton-canvas-size: var(--dimension-iconography-sm); }
:host(.skeleton--icon-md)  { --ds-skeleton-canvas-size: var(--dimension-iconography-md); }
:host(.skeleton--icon-lg)  { --ds-skeleton-canvas-size: var(--dimension-iconography-lg); }
:host(.skeleton--icon-xl)  { --ds-skeleton-canvas-size: var(--dimension-iconography-xl); }
:host(.skeleton--icon-2xl) { --ds-skeleton-canvas-size: var(--dimension-iconography-2xl); }
:host(.skeleton--icon-3xl) { --ds-skeleton-canvas-size: var(--dimension-iconography-3xl); }

/* ── Control ───────────────────────────────────────────────────────────── */

:host(.skeleton--control) {
  width: 100%;
  height: var(--ds-control-height);
}

:host(.skeleton--control.skeleton--rounded) .skeleton__shape {
  border-radius: var(--dimension-radius-half);
}

import type { Meta, StoryObj } from '@storybook/web-components';
import { html } from 'lit';
import '../../../../dist/components/ds-skeleton.js';
import '../../../../dist/components/ds-text.js';

const TEXT_VARIANTS = [
  'text-display-medium',
  'text-display-small',
  'text-title-large',
  'text-title-medium',
  'text-title-small',
  'text-body-large',
  'text-body-medium',
  'text-body-small',
  'text-caption',
] as const;

const ICON_SIZES = ['xs', 'sm', 'md', 'lg', 'xl', '2xl', '3xl'] as const;
const CONTROL_SIZES = ['xs', 'sm', 'md'] as const;

const meta: Meta = {
  title: 'Primitives/Skeleton',
  tags: ['autodocs'],
  argTypes: {
    variant: { control: 'select', options: ['text', 'icon', 'control'] },
    textVariant: { control: 'select', options: TEXT_VARIANTS },
    iconSize: { control: 'select', options: ICON_SIZES },
    controlSize: { control: 'select', options: CONTROL_SIZES },
    width: { control: 'text' },
    rounded: { control: 'boolean' },
    shimmer: { control: 'boolean' },
  },
  args: {
    variant: 'text',
    textVariant: 'text-body-medium',
    iconSize: 'md',
    controlSize: 'md',
    width: '240px',
    rounded: false,
    shimmer: true,
  },
};

export default meta;
type Story = StoryObj;

export const Playground: Story = {
  render: args => html`
    <ds-skeleton
      variant=${args['variant']}
      text-variant=${args['textVariant']}
      icon-size=${args['iconSize']}
      control-size=${args['controlSize']}
      width=${args['width']}
      ?rounded=${args['rounded']}
      ?shimmer=${args['shimmer']}
    ></ds-skeleton>
  `,
};

export const TextCanvases: Story = {
  name: 'Text canvases',
  render: () => html`
    <div style="display: flex; flex-direction: column; gap: var(--dimension-space-100); width: 420px;">
      ${TEXT_VARIANTS.map(variant => html`
        <div style="display: grid; grid-template-columns: 160px 1fr; align-items: center; gap: var(--dimension-space-200);">
          <ds-text variant="text-body-small" color="secondary">${variant}</ds-text>
          <ds-skeleton variant="text" text-variant=${variant} width="100%"></ds-skeleton>
        </div>
      `)}
    </div>
  `,
};

export const ComposedTextLines: Story = {
  name: 'Composed text lines',
  render: () => html`
    <div style="display: flex; flex-direction: column; width: 320px;">
      <ds-skeleton variant="text" text-variant="text-body-medium" width="100%"></ds-skeleton>
      <ds-skeleton variant="text" text-variant="text-body-medium" width="88%"></ds-skeleton>
      <ds-skeleton variant="text" text-variant="text-body-medium" width="60%"></ds-skeleton>
    </div>
  `,
};

export const IconCanvases: Story = {
  name: 'Icon canvases',
  render: () => html`
    <div style="display: flex; align-items: flex-end; gap: var(--dimension-space-200);">
      ${ICON_SIZES.map(size => html`
        <div style="display: flex; flex-direction: column; align-items: center; gap: var(--dimension-space-075);">
          <ds-skeleton variant="icon" icon-size=${size}></ds-skeleton>
          <ds-text variant="text-body-small" color="secondary">${size}</ds-text>
        </div>
      `)}
    </div>
  `,
};

export const ControlCanvases: Story = {
  name: 'Control canvases',
  render: () => html`
    <div style="display: flex; flex-direction: column; align-items: flex-start; gap: var(--dimension-space-150);">
      ${CONTROL_SIZES.map(size => html`
        <div style="display: flex; align-items: center; gap: var(--dimension-space-200);">
          <ds-text variant="text-body-small" color="secondary" style="width: 24px;">${size}</ds-text>
          <ds-skeleton variant="control" control-size=${size} width="160px"></ds-skeleton>
          <ds-skeleton variant="control" control-size=${size} width="96px" rounded></ds-skeleton>
        </div>
      `)}
    </div>
  `,
};

export const Composition: Story = {
  render: () => html`
    <div style="display: flex; align-items: flex-start; gap: var(--dimension-space-150); width: 360px; padding: var(--dimension-space-200); border: var(--dimension-stroke-width-015) solid var(--color-border-secondary); border-radius: var(--dimension-radius-150);">
      <ds-skeleton variant="icon" icon-size="md"></ds-skeleton>
      <div style="display: flex; flex: 1; flex-direction: column; gap: var(--dimension-space-100);">
        <div style="display: flex; flex-direction: column;">
          <ds-skeleton variant="text" text-variant="text-body-medium" width="72%"></ds-skeleton>
          <ds-skeleton variant="text" text-variant="text-body-small" width="48%"></ds-skeleton>
        </div>
        <ds-skeleton variant="control" control-size="sm" width="96px" rounded></ds-skeleton>
      </div>
    </div>
  `,
};

import { Component, Prop, h, Host } from '@stencil/core';
import type { IconSize } from '../Icon/Icon';
import type { TextVariant } from '../Text/text-types';
import type { ControlSize } from '../../utils/control-text';

export type SkeletonVariant = 'text' | 'icon' | 'control';

@Component({
  tag: 'ds-skeleton',
  styleUrl: 'Skeleton.css',
  shadow: true,
})
export class Skeleton {
  @Prop() variant: SkeletonVariant = 'text';
  /** Text metric recipe whose line-height defines the text canvas. */
  @Prop() textVariant: TextVariant = 'text-body-medium';
  /** Iconography token whose square canvas defines the icon canvas. */
  @Prop() iconSize: IconSize = 'md';
  /** Shared control-density size whose height defines the control canvas. */
  @Prop() controlSize: ControlSize = 'md';
  /** Width of text and control skeleton canvases. Numbers resolve to px. Ignored for icons. */
  @Prop() width: string | number | undefined;
  /** Round icon skeletons into circles and control skeletons into pills. Ignored for text. */
  @Prop() rounded: boolean = false;
  /** Whether to show the shimmer animation. */
  @Prop() shimmer: boolean = true;

  private get widthCss() {
    const v = this.width;
    if (v == null) return undefined;
    return typeof v === 'number' ? `${v}px` : v;
  }

  render() {
    return (
      <Host
        aria-hidden="true"
        class={{
          'skeleton': true,
          [`skeleton--${this.variant}`]: true,
          [`skeleton--text-${this.textVariant}`]: this.variant === 'text',
          [`skeleton--icon-${this.iconSize}`]: this.variant === 'icon',
          [`ds-control--${this.controlSize}`]: this.variant === 'control',
          'skeleton--rounded': this.variant !== 'text' && this.rounded,
        }}
        style={this.variant === 'icon' ? undefined : { width: this.widthCss }}
      >
        <span
          class={{
            'skeleton__shape': true,
            'ds-shimmer-surface': this.shimmer,
          }}
        />
      </Host>
    );
  }
}
